targets.expr:
(
  sum by (caught) (
    clamp_min(irate(cast_total{job=~"$job", caught="false"}[1m]), 0)
  )
  + on (caught)
  label_set(
    sum(
      clamp_min(irate(hook_total{job=~"$job", result="escaped"}[1m]), 0)
    ),
    "caught","false"
  )
)
or
sum by (caught) (
  clamp_min(irate(cast_total{job=~"$job", caught="false"}[1m]), 0)
)
or
label_set(
  sum(
    clamp_min(irate(hook_total{job=~"$job", result="escaped"}[1m]), 0)
  ),
  "caught","false"
)
